;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const odssDropdown={elements:{dropdowns:[...document.querySelectorAll(".odss-dropdown")]},methods:{initialize:()=>{odssDropdown.events.clickEvents();},toggle:event=>{const dropdown=event.target.closest(".odss-dropdown");odssDropdown.methods.closeDropdowns([dropdown]);const open=dropdown?.classList.toggle("odss-dropdown--open");odssDropdown.methods.fixPosition(dropdown,open);},fixPosition:(dropdown,open)=>{const content=dropdown.querySelector(".odss-dropdown__content");content.style.marginLeft="";if(open){const bounding=content.getBoundingClientRect();const offsetRight=bounding?bounding.right-(window.innerWidth||document.documentElement.clientWidth):0;if(offsetRight>0){content.style.marginLeft=`-${Math.round(offsetRight)}px`;}}},closeDropdowns:(excluded=[])=>{odssDropdown.elements.dropdowns.forEach(dropdown=>{if(!excluded.includes(dropdown)){dropdown.classList.remove("odss-dropdown--open");}});}},events:{clickEvents(){odssDropdown.elements.dropdowns.forEach(dropdown=>{dropdown.addEventListener("mousedown",event=>{event.stopPropagation();});const dropdownTitle=dropdown.querySelector(".odss-dropdown__title");dropdownTitle.addEventListener("mousedown",odssDropdown.methods.toggle);dropdownTitle.addEventListener("keypress",event=>{if(["Enter"," "].includes(event.key)){event.preventDefault();odssDropdown.methods.toggle(event);}});});window.addEventListener("mousedown",()=>{odssDropdown.methods.closeDropdowns();});}},attach:()=>odssDropdown.methods.initialize()};Drupal2.behaviors.odssDropdown=odssDropdown;})(Drupal);}};});})();
